import boto3, os, mimetypes
from pathlib import PurePosixPath

s3 = boto3.client("s3", region_name=os.environ.get("AWS_REGION", "us-east-1"))
BUCKET = os.environ["S3_BUCKET"]

def _safe_key(tenant_id: str, user_id: str, filename: str) -> str:
    """Build an S3 key scoped to this user. Strips any path traversal attempts."""
    safe_name = PurePosixPath(filename).name   # removes any directory components
    return f"uploads/{tenant_id}/{user_id}/{safe_name}"

def upload_file(tenant_id: str, user_id: str, filename: str, data: bytes) -> str:
    key = _safe_key(tenant_id, user_id, filename)
    content_type = mimetypes.guess_type(filename)[0] or "application/octet-stream"
    s3.put_object(Bucket=BUCKET, Key=key, Body=data, ContentType=content_type)
    return key

def download_file(tenant_id: str, user_id: str, filename: str) -> bytes:
    key = _safe_key(tenant_id, user_id, filename)
    response = s3.get_object(Bucket=BUCKET, Key=key)
    return response["Body"].read()

def list_user_files(tenant_id: str, user_id: str) -> list[str]:
    prefix = f"uploads/{tenant_id}/{user_id}/"
    paginator = s3.get_paginator("list_objects_v2")
    names = []
    for page in paginator.paginate(Bucket=BUCKET, Prefix=prefix):
        for obj in page.get("Contents", []):
            names.append(obj["Key"][len(prefix):])   # strip prefix, return filename only
    return names

# Tool definitions for the agent:
def make_file_tools(tenant_id: str, user_id: str) -> list[dict]:
    return [
        {
            "name": "list_my_files",
            "description": "List files the user has uploaded.",
            "input_schema": {"type": "object", "properties": {}},
        },
        {
            "name": "read_my_file",
            "description": "Read a file the user has uploaded.",
            "input_schema": {
                "type": "object",
                "properties": {"filename": {"type": "string"}},
                "required": ["filename"],
            },
        },
    ]

def execute_file_tool(name: str, inputs: dict, tenant_id: str, user_id: str) -> str:
    import json
    if name == "list_my_files":
        return json.dumps(list_user_files(tenant_id, user_id))
    if name == "read_my_file":
        data = download_file(tenant_id, user_id, inputs["filename"])
        return data.decode("utf-8", errors="replace")[:8000]   # token budget guard
    return json.dumps({"error": "unknown"})

import redis, os, time, json
from anthropic import Anthropic

r = redis.Redis.from_url(os.environ["REDIS_URL"], decode_responses=True)
client = Anthropic()

DAILY_TOKEN_LIMIT = {
    "starter":    50_000,
    "pro":       500_000,
    "enterprise": 5_000_000,
}

def _usage_key(tenant_id: str, user_id: str) -> str:
    day = time.strftime("%Y-%m-%d")
    return f"usage:{tenant_id}:{user_id}:{day}"

def get_user_usage(tenant_id: str, user_id: str) -> int:
    val = r.get(_usage_key(tenant_id, user_id))
    return int(val) if val else 0

def increment_usage(tenant_id: str, user_id: str, tokens: int) -> int:
    key = _usage_key(tenant_id, user_id)
    total = r.incrby(key, tokens)
    if r.ttl(key) < 0:
        r.expire(key, 86400 * 2)   # 2-day TTL (today + yesterday buffer)
    return total

def check_quota(tenant_id: str, user_id: str, plan: str) -> None:
    limit = DAILY_TOKEN_LIMIT.get(plan, 50_000)
    used  = get_user_usage(tenant_id, user_id)
    if used >= limit:
        raise RuntimeError(
            f"Daily token limit reached ({used}/{limit}). Resets at midnight UTC."
        )

def run_agent_with_quota(message: str, tools: list[dict], tenant_id: str,
                          user_id: str, plan: str) -> str:
    check_quota(tenant_id, user_id, plan)
    messages = [{"role": "user", "content": message}]
    total_tokens = 0

    while True:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=800,
            tools=tools,
            messages=messages,
        )
        total_tokens += resp.usage.input_tokens + resp.usage.output_tokens

        if resp.stop_reason == "end_turn":
            increment_usage(tenant_id, user_id, total_tokens)
            return next((b.text for b in resp.content if b.type == "text"), "")

        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = json.dumps({"result": "..."})   # placeholder
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]
